'use client';

import { useAuth } from '@/context/AuthContext';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';
import { supabase } from '@/lib/supabaseClient';
import Navbar from 'components/Navbar';

export default function ProfilePage() {
  const { user } = useAuth();
  const router = useRouter();
  const [profile, setProfile] = useState(null);

  useEffect(() => {
    if (!user) {
      router.push('/auth');
    } else {
      fetchProfile();
    }
  }, [user]);

  const fetchProfile = async () => {
    const { data, error } = await supabase
      .from('profiles')
      .select('*')
      .eq('id', user.id)
      .single();

    if (!error) setProfile(data);
  };

  if (!user || !profile) return null;

  return (
    <div className="min-h-screen bg-gray-100">
      <Navbar />

      <div className="max-w-6xl mx-auto grid grid-cols-1 md:grid-cols-4 gap-6 p-6">
        {/* Left Profile Summary */}
        <aside className="col-span-1 bg-white shadow p-4 rounded-md text-center">
          <div className="w-24 h-24 bg-gray-300 rounded-full mx-auto mb-2" />
          <h2 className="text-lg font-semibold">
            {profile.name || 'Unnamed User'}
          </h2>
          <p className="text-sm text-gray-500">{profile.email}</p>
          <p className="text-xs mt-2 text-gray-400">
            Connections: 0 | Views: 0
          </p>
        </aside>

        {/* Main Profile Details */}
        <section className="col-span-3 bg-white shadow p-6 rounded-md space-y-6">
          <div>
            <h3 className="font-semibold text-lg">Bio</h3>
            <p className="text-sm text-gray-700">
              {profile.bio || 'No bio yet.'}
            </p>
          </div>

          <div>
            <h3 className="font-semibold text-lg">Portfolio</h3>
            <p className="text-sm text-gray-700">
              {profile.portfolio_url
                ? `Portfolio: ${profile.portfolio_url}`
                : 'No portfolio linked yet.'}
            </p>
          </div>

          <div>
            <h3 className="font-semibold text-lg">Mediums</h3>
            <p className="text-sm text-gray-700">
              {profile.mediums?.length > 0
                ? profile.mediums.join(', ')
                : 'No mediums selected.'}
            </p>
          </div>

          <div>
            <h3 className="font-semibold text-lg">Accomplishments</h3>
            <p className="text-sm text-gray-700">
              {profile.accomplishments || 'No accomplishments listed.'}
            </p>
          </div>
        </section>
      </div>
    </div>
  );
}
